import SwiftUI

enum AppLanguage: String, CaseIterable, Identifiable {
    case en = "en"
    case zhHans = "zh-Hans"
    case zhHant = "zh-Hant"
    case ja = "ja"
    case ko = "ko"
    case fr = "fr"
    case de = "de"
    case es = "es"
    case pt = "pt"
    case it = "it"
    case ru = "ru"
    case ar = "ar"
    case hi = "hi"
    case tr = "tr"
    case vi = "vi"
    case th = "th"
    case id = "id"
    case nl = "nl"
    case pl = "pl"
    case ms = "ms"
    
    var id: String { self.rawValue }
    
    var displayName: String {
        switch self {
        case .en: return "English"
        case .zhHans: return "简体中文"
        case .zhHant: return "繁體中文"
        case .ja: return "日本語"
        case .ko: return "한국어"
        case .fr: return "Français"
        case .de: return "Deutsch"
        case .es: return "Español"
        case .pt: return "Português"
        case .it: return "Italiano"
        case .ru: return "Русский"
        case .ar: return "العربية"
        case .hi: return "हिन्दी"
        case .tr: return "Türkçe"
        case .vi: return "Tiếng Việt"
        case .th: return "ไทย"
        case .id: return "Bahasa Indonesia"
        case .nl: return "Nederlands"
        case .pl: return "Polski"
        case .ms: return "Bahasa Melayu"
        }
    }
}

@MainActor
class LanguageManager: ObservableObject {
    var selectedLanguage: AppLanguage {
        get {
            let raw = UserDefaults.standard.string(forKey: "app_language") ?? "en"
            return AppLanguage(rawValue: raw) ?? .en
        }
        set {
            UserDefaults.standard.set(newValue.rawValue, forKey: "app_language")
            objectWillChange.send()
        }
    }
    var hasSetInitialLanguage: Bool {
        get { UserDefaults.standard.bool(forKey: "has_set_initial_language") }
        set { UserDefaults.standard.set(newValue, forKey: "has_set_initial_language") }
    }
    
    static let shared = LanguageManager()
    
    private init() {
        if !hasSetInitialLanguage {
            detectAndSetSystemLanguage()
        }
    }
    
    private func detectAndSetSystemLanguage() {
        let systemLanguageCode: String
        if #available(iOS 16, *) {
            systemLanguageCode = Locale.current.language.languageCode?.identifier ?? "en"
        } else {
            systemLanguageCode = Locale.current.languageCode ?? "en"
        }
        
        // Map system code to our AppLanguage
        if let matchedLanguage = AppLanguage.allCases.first(where: { $0.rawValue.hasPrefix(systemLanguageCode) }) {
            selectedLanguage = matchedLanguage
        } else {
            selectedLanguage = .en
        }
        hasSetInitialLanguage = true
    }
    
    nonisolated func localizedString(for key: String) -> String {
        let raw = UserDefaults.standard.string(forKey: "app_language") ?? "en"
        let language = AppLanguage(rawValue: raw)?.rawValue ?? "en"
        return Self.translations[language]?[key] ?? Self.translations["en"]?[key] ?? key
    }
    
    private final class _TranslationsBox: @unchecked Sendable {
        let lock = NSLock()
        var value: [String: [String: String]]?
    }
    
    nonisolated private static let _translationsBox = _TranslationsBox()
    
    nonisolated private static var translations: [String: [String: String]] {
        get {
            if let cached = _translationsBox.value { return cached }
            _translationsBox.lock.lock()
            defer { _translationsBox.lock.unlock() }
            if let cached = _translationsBox.value { return cached }
            let loaded = loadTranslations()
            _translationsBox.value = loaded
            return loaded
        }
    }
    
